//   in the resulting array, giving us alternating [nonMatch, match, nonMatch…]
//   segments that we can map over and selectively wrap.
// ---------------------------------------------------------------------------
function HighlightedText({ text, query }) {
    if (!query) return <>{text}</>;

    const regex = new RegExp(`(${escapeRegex(query)})`, 'gi');
